    }

    public Node(int _val, List<Node> _children) {
        val = _val;
        children = _children;
    }
};
*/

class Solution {
    public int maxDepth(Node root) {
        if (root == null) {
            return 0;
        }
        int mx = 0;
        for (Node child : root.children) {
            mx = Math.max(mx, maxDepth(child));
        }
        return 1 + mx;
    }
}

